mapper.sql:
SELECT ID, PREPAYMENT_CODE, COMPANY_NAME, COMPANY_ID, PREPAYMENT_TYPE_CODE, PREPAYMENT_TYPE_NAME, CUSTOMER_ID, CUSTOMER_NAME, PREPAYMENT_TIME, PREPAYMENT_AMOUNT, UTILIZED_AMOUNT, PAYMENT_METHOD_CODE, PAYMENT_METHOD_NAME, BANK_NAME, BANK_ID, STATUS, REMARK, TRANS_SEQUENCE_IDN CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, TRUST_NO, BUS_TRUST_ID, BUS_TRUST_CARGO_ID FROM T_FD_BANK_CUSTOMER_PREPAYMENT
and ID = #{id}
and PREPAYMENT_CODE LIKE #{prepaymentCode_like}
and COMPANY_ID = #{companyId}
and PREPAYMENT_TYPE_CODE = #{prepaymentTypeCode}
and CUSTOMER_ID = #{customerId}
and PREPAYMENT_TIME = #{prepaymentTime}
and UTILIZED_AMOUNT = #{utilizedAmount}
and PAYMENT_METHOD_CODE = #{paymentMethodCode}
and BANK_NAME = #{bankName}
and BANK_ID = #{bankId}
and STATUS = #{status}
and PREPAYMENT_TIME >= #{startTime,jdbcType=DATE}
and PREPAYMENT_TIME <= #{endTime,jdbcType=DATE}
ORDER BY CREATE_TIME DESC

mapper.select:
select * FROM ( SELECT TFBCP.ID, TFBCP.TRUST_NO, TFBCP.PREPAYMENT_CODE, TFBCP.COMPANY_NAME, TFBCP.COMPANY_ID, TFBCP.PREPAYMENT_TYPE_CODE, TFBCP.PREPAYMENT_TYPE_NAME, TFBCP.CUSTOMER_ID, TFBCP.CUSTOMER_NAME, TFBCP.PREPAYMENT_TIME, TFBCP.PREPAYMENT_AMOUNT, TFBCP.UTILIZED_AMOUNT, TFBCP.PAYMENT_METHOD_CODE, TFBCP.PAYMENT_METHOD_NAME, TFBCP.BANK_NAME, TFBCP.BANK_ID, TFBCP.STATUS, TFBCP.REMARK, TFBCP.TRANS_SEQUENCE_IDN, TFBCP.CREATE_BY, TFBCP.CREATE_BY_NAME, TFBCP.CREATE_TIME, TFBCP.UPDATE_BY, TFBCP.UPDATE_BY_NAME, TFBCP.UPDATE_TIME, TFBCP.VOID_BY, TFBCP.VOID_BY_NAME, TFBCP.VOID_TIME, TFBCP.BUS_TRUST_ID, TFBCP.BUS_TRUST_CARGO_ID, PREPAY_MODE_NAME, PREPAY_MODE_CODE, SOURCE_PREPAY_CODE, CASE WHEN TDS.SHIP_NAME IS NULL AND TFBCP.BUS_TRUST_ID IS NOT NULL THEN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( TDS.SHIP_NAME )|| '_' || TO_CHAR( TDSI.VOYAGE ), ',' ) WITHIN GROUP ( ORDER BY TDS.SHIP_NAME), '([^,]+)(,\1)+','\1' ) AS "shipVoyageName" FROM T_BUS_TRUST TBT LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID LEFT JOIN T_DIS_SHIPVOYAGE TDS on TBCI.SHIPVOYAGE_ID = TDS.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI on TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID WHERE TFBCP.BUS_TRUST_ID = TBT.ID ) ELSE TO_CHAR( TDS.SHIP_NAME )|| '_' || TO_CHAR( TDSI.VOYAGE ) END "shipVoyageName",
CASE WHEN TDS.SHIP_NAME IS NULL AND TFBCP.BUS_TRUST_ID IS NOT NULL THEN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( TBT.SHIPVOYAGE_ITEM_ID), ',' ) WITHIN GROUP ( ORDER BY TDS.SHIP_NAME), '([^,]+)(,\1)+', '\1' ) AS "shipVoyageIds" FROM T_BUS_TRUST TBT LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID LEFT JOIN T_DIS_SHIPVOYAGE TDS on TBCI.SHIPVOYAGE_ID = TDS.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI on TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID WHERE TFBCP.BUS_TRUST_ID = TBT.ID ) ELSE to_char(TBT.SHIPVOYAGE_ITEM_ID) END "shipVoyageIds"
FROM T_FD_BANK_CUSTOMER_PREPAYMENT TFBCP LEFT JOIN T_BUS_TRUST TBT ON TFBCP.BUS_TRUST_ID = TBT.ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TBT.SHIPVOYAGE_ID = TDS.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI on TBT.SHIPVOYAGE_ITEM_ID = TDSI.ID
and TFBCP.ID = #{id}
and TFBCP.PREPAYMENT_CODE LIKE #{prepaymentCode_like}
and TFBCP.COMPANY_ID = #{companyId}
and TFBCP.PREPAYMENT_TYPE_CODE = #{prepaymentTypeCode}
and TFBCP.CUSTOMER_ID = #{customerId}
and TFBCP.PREPAYMENT_TIME = #{prepaymentTime}
and TFBCP.UTILIZED_AMOUNT = #{utilizedAmount}
and TFBCP.PAYMENT_METHOD_CODE = #{paymentMethodCode}
and TFBCP.BANK_NAME = #{bankName}
and TBT.TRUST_NO LIKE #{trustNo_like}
and TFBCP.BANK_ID = #{bankId}
and TFBCP.STATUS = #{status}
and TFBCP.PREPAYMENT_TIME >= #{startTime,jdbcType=DATE}
and TFBCP.PREPAYMENT_TIME <= #{endTime,jdbcType=DATE}
)
AND "shipVoyageIds" LIKE #{shipvoyageItemId_like}
ORDER BY CREATE_TIME DESC

SELECT T1.COMPANY_ID,T1.COMPANY_NAME,T1.CUSTOMER_ID,T1.CUSTOMER_NAME,T1.PREPAYMENT_TYPE_CODE, T1.PREPAYMENT_TYPE_NAME, T1.ALL_PREPAYMENT_AMOUNT,T1.PREPAYMENT_AMOUNT,T1.UTILIZED_AMOUNT, T1.INVOICE_AMOUNT,T1.CARGO_DEPOSIT,NVL(T2.PAYMENT_AMOUNT,0) SHIP_DEPOSIT,CARGO_DEPOSIT_CAN FROM ( SELECT T.COMPANY_ID,T.COMPANY_NAME,T.CUSTOMER_ID,T.CUSTOMER_NAME, T.PREPAYMENT_TYPE_CODE,T.PREPAYMENT_TYPE_NAME, NVL(SUM(DECODE(T.PREPAY_MODE_CODE,'10',T.PREPAYMENT_AMOUNT,0)),0) AS ALL_PREPAYMENT_AMOUNT, NVL(SUM(T.PREPAYMENT_AMOUNT),0) AS PREPAYMENT_AMOUNT, NVL(SUM(T.UTILIZED_AMOUNT),0) AS UTILIZED_AMOUNT, NVL(SUM(T.INVOICE_AMOUNT),0) AS INVOICE_AMOUNT, sum(nvl(CARGO_DEPOSIT_CAN,0)) CARGO_DEPOSIT_CAN,
NVL(SUM(T.CARGO_DEPOSIT),0) CARGO_DEPOSIT FROM ( SELECT COMPANY_ID,COMPANY_NAME,CUSTOMER_ID,CUSTOMER_NAME,PREPAYMENT_TYPE_CODE,PREPAYMENT_TYPE_NAME, PREPAYMENT_AMOUNT,UTILIZED_AMOUNT,0.00 AS INVOICE_AMOUNT,TO_CHAR(PREPAY_MODE_CODE) AS PREPAY_MODE_CODE, DECODE(PREPAY_MODE_CODE,'20',PREPAYMENT_AMOUNT,0) CARGO_DEPOSIT, DECODE(PREPAY_MODE_CODE,'20',PREPAYMENT_AMOUNT-T_FD_BANK_CUSTOMER_PREPAYMENT.UTILIZED_AMOUNT,0) CARGO_DEPOSIT_CAN FROM T_FD_BANK_CUSTOMER_PREPAYMENT WHERE STATUS = 1 UNION ALL SELECT COMPANY_ID,COMPANY_NAME,CUSTOMER_ID,CUSTOMER_NAME,cast(TO_CHAR(PREPAYMENT_TYPE_CODE) AS nvarchar2(50)),PREPAYMENT_TYPE_NAME, 0.00 AS PREPAYMENT_AMOUNT,0.00 AS UTILIZED_AMOUNT,HAS_NOT_RECEIPT_AMOUNT INVOICE_AMOUNT,TO_CHAR('') AS PREPAY_MODE_CODE,0.00,0.00 FROM T_FD_INVOICE WHERE STATUS = 1
) T GROUP BY T.COMPANY_ID,T.COMPANY_NAME,T.CUSTOMER_ID,T.CUSTOMER_NAME,T.PREPAYMENT_TYPE_CODE,T.PREPAYMENT_TYPE_NAME ) T1 LEFT JOIN ( SELECT TDSI.CUSTOMER_ID,NVL(SUM(TDSI.PAYMENT_AMOUNT),0) AS PAYMENT_AMOUNT FROM T_DIS_SHIPVOYAGE TDS INNER JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TDS.ID = TDSI.SHIPVOYAGE_ID WHERE TDS.DEL_FLAG = '0' GROUP BY TDSI.CUSTOMER_ID ) T2 ON T1.CUSTOMER_ID = T2.CUSTOMER_ID
and T1.COMPANY_ID = #{companyId}
and T1.PREPAYMENT_TYPE_CODE = #{prepaymentTypeCode}
and T1.CUSTOMER_ID = #{customerId}
ORDER BY T1.CUSTOMER_NAME,T1.CUSTOMER_ID

SELECT * FROM ( SELECT TO_CHAR(TFBCP.PREPAY_MODE_NAME) AS DETAIL_TYPE, DECODE(TFBCP.PREPAY_MODE_CODE,20,TFBCP.PREPAYMENT_AMOUNT * -1,TFBCP.PREPAYMENT_AMOUNT) AS AMOUNT, '' "shipVoyageName", TFBCP.CREATE_TIME PAYMENT_TIME, TFBCP.CUSTOMER_ID, TO_CHAR(TFBCP.PREPAYMENT_TYPE_CODE) AS PREPAYMENT_TYPE_CODE, TO_CHAR(TFBCP.PREPAYMENT_CODE) AS BUSINESS_NO, TFBCP.CREATE_BY_NAME, TFBCP.COMPANY_NAME FROM T_FD_BANK_CUSTOMER_PREPAYMENT TFBCP WHERE TFBCP.SOURCE_DEBTORPAYMENT_ID IS NULL AND TFBCP.STATUS = 1 UNION ALL SELECT TO_CHAR(TFBCP.PREPAY_MODE_NAME) AS DETAIL_TYPE, TFBCP.PREPAYMENT_AMOUNT, '' "shipVoyageName", TFBCP.CREATE_TIME, TFBCP.CUSTOMER_ID, TO_CHAR(TFBCP.PREPAYMENT_TYPE_CODE), TO_CHAR(TFBCP.PREPAYMENT_CODE) AS BUSINESS_NO, TFBCP.CREATE_BY_NAME, TFBCP.COMPANY_NAME FROM T_FD_BANK_CUSTOMER_PREPAYMENT TFBCP INNER JOIN T_FD_DEBTORPAYMENT TFD ON TFBCP.SOURCE_DEBTORPAYMENT_ID = TFD.ID INNER JOIN T_FD_DEBTORPAYMENT_DETAIL TFDD ON TFD.ID = TFDD.DEBTORPAYMENT_ID WHERE TFBCP.SOURCE_DEBTORPAYMENT_ID IS NOT NULL AND TFBCP.STATUS = 1 AND TFD.STATUS = 1 AND TFDD.DEBTORPAY_PAYMENT_TYPE_CODE = '20' UNION ALL SELECT '船舶押金' AS DETAIL_TYPE, DECODE(TDSI.PAYMENT_AMOUNT,NULL,0,TDSI.PAYMENT_AMOUNT * -1) AS AMOUNT, to_char(tds.ship_name || '_' || tdsi.voyage) "shipVoyageName", TDSI.CREATE_TIME, TDSI.CUSTOMER_ID, TO_CHAR('30'), '', TDSI.CREATE_BY_NAME, tdsi.COMPANY_NAME FROM T_DIS_SHIPVOYAGE TDS INNER JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TDS.ID = TDSI.SHIPVOYAGE_ID WHERE TDS.DEL_FLAG = '0' and ABS(nvl(DECODE(TDSI.PAYMENT_AMOUNT,NULL,0,TDSI.PAYMENT_AMOUNT * -1),0)) !=0 UNION ALL SELECT '发票' AS DETAIL_TYPE, DECODE(TFI.INVOICE_AMOUNT,NULL,0,TFI.INVOICE_AMOUNT * -1), ttt.ship_name "shipVoyageName", TFI.CREATE_TIME, TFI.CUSTOMER_ID, TO_CHAR(TFI.PREPAYMENT_TYPE_CODE), TO_CHAR(TFI.SYS_INVOICE_CODE), TFI.CREATE_BY_NAME, tfi.COMPANY_NAME
FROM T_FD_INVOICE TFI left join (select INVOICE_ID, REGEXP_REPLACE ( LISTAGG (TO_CHAR(TFID.SHIP_NAME||'_'||TFID.VOYAGE), ',') WITHIN GROUP (ORDER BY INVOICE_ID), '([^,]+)(,\1)+', '\1' ) ship_name from T_FD_INVOICE_DETAIL TFID group by TFID.INVOICE_ID) ttt on ttt.INVOICE_ID = TFI.id WHERE TFI.STATUS = 1 and TFI.CREATE_TIME>TO_DATE('2024-10-31 12:00:00', 'YYYY-MM-DD HH24:MI:SS') UNION ALL SELECT '退还' AS DETAIL_TYPE, DECODE(TFDD.INVOICE_PREPAY_AMOUNT,NULL,0,TFDD.INVOICE_PREPAY_AMOUNT * -1) AS AMOUNT, '' "shipVoyageName", TO_DATE(TFDD.CREATE_TIME,'YYYY-MM-DD HH24:MI:SS'), TFD.CUSTOMER_ID, TO_CHAR(TFD.PREPAYMENT_TYPE_CODE), TO_CHAR(TFD.DEBTORPAYMENT_NO), TFDD.CREATE_BY_NAME, TFD.COMPANY_NAME
FROM T_FD_DEBTORPAYMENT TFD INNER JOIN T_FD_DEBTORPAYMENT_DETAIL TFDD ON TFD.ID = TFDD.DEBTORPAYMENT_ID WHERE TFD.STATUS = 1 AND TFDD.DEBTORPAY_PAYMENT_TYPE_CODE = '30' ) T
T.CUSTOMER_ID = #{customerId,jdbcType=VARCHAR} AND T.PREPAYMENT_TYPE_CODE = #{prepaymentTypeCode,jdbcType=VARCHAR}
and to_char(T.PAYMENT_TIME,'YYYY-MM-DD') >= #{searchStartTime}
and to_char(T.PAYMENT_TIME,'YYYY-MM-DD') <= #{searchEndTime}
and T.BUSINESS_NO LIKE #{businessNoLike}
and T.DETAIL_TYPE NOT IN ('货物预缴','船舶押金')
ORDER BY T.PAYMENT_TIME DESC

SELECT * FROM ( SELECT TO_CHAR(TFBCP.PREPAY_MODE_NAME) AS DETAIL_TYPE, DECODE(TFBCP.PREPAY_MODE_CODE,20,TFBCP.PREPAYMENT_AMOUNT * -1,TFBCP.PREPAYMENT_AMOUNT) AS AMOUNT, '' "shipVoyageName", TFBCP.CREATE_TIME PAYMENT_TIME, TFBCP.CUSTOMER_ID, TO_CHAR(TFBCP.PREPAYMENT_TYPE_CODE) AS PREPAYMENT_TYPE_CODE, TO_CHAR(TFBCP.PREPAYMENT_CODE) AS BUSINESS_NO, TFBCP.CREATE_BY_NAME, TFBCP.COMPANY_NAME FROM T_FD_BANK_CUSTOMER_PREPAYMENT TFBCP WHERE TFBCP.SOURCE_DEBTORPAYMENT_ID IS NULL AND TFBCP.STATUS = 1 UNION ALL SELECT TO_CHAR(TFBCP.PREPAY_MODE_NAME) AS DETAIL_TYPE, TFBCP.PREPAYMENT_AMOUNT, '' "shipVoyageName", TFBCP.CREATE_TIME, TFBCP.CUSTOMER_ID, TO_CHAR(TFBCP.PREPAYMENT_TYPE_CODE), TO_CHAR(TFBCP.PREPAYMENT_CODE) AS BUSINESS_NO, TFBCP.CREATE_BY_NAME, TFBCP.COMPANY_NAME FROM T_FD_BANK_CUSTOMER_PREPAYMENT TFBCP INNER JOIN T_FD_DEBTORPAYMENT TFD ON TFBCP.SOURCE_DEBTORPAYMENT_ID = TFD.ID INNER JOIN T_FD_DEBTORPAYMENT_DETAIL TFDD ON TFD.ID = TFDD.DEBTORPAYMENT_ID WHERE TFBCP.SOURCE_DEBTORPAYMENT_ID IS NOT NULL AND TFBCP.STATUS = 1 AND TFD.STATUS = 1 AND TFDD.DEBTORPAY_PAYMENT_TYPE_CODE = '20' UNION ALL SELECT '船舶押金' AS DETAIL_TYPE, DECODE(TDSI.PAYMENT_AMOUNT,NULL,0,TDSI.PAYMENT_AMOUNT * -1) AS AMOUNT, to_char(tds.ship_name || '_' || tdsi.voyage) "shipVoyageName", TDSI.CREATE_TIME, TDSI.CUSTOMER_ID, TO_CHAR('30'), '', TDSI.CREATE_BY_NAME, tdsi.COMPANY_NAME FROM T_DIS_SHIPVOYAGE TDS INNER JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TDS.ID = TDSI.SHIPVOYAGE_ID WHERE TDS.DEL_FLAG = '0' and ABS(nvl(DECODE(TDSI.PAYMENT_AMOUNT,NULL,0,TDSI.PAYMENT_AMOUNT * -1),0)) !=0 UNION ALL SELECT '发票' AS DETAIL_TYPE, DECODE(TFI.INVOICE_AMOUNT,NULL,0,TFI.INVOICE_AMOUNT * -1), ttt.ship_name "shipVoyageName", TFI.CREATE_TIME, TFI.CUSTOMER_ID, TO_CHAR(TFI.PREPAYMENT_TYPE_CODE), TO_CHAR(TFI.SYS_INVOICE_CODE), TFI.CREATE_BY_NAME, tfi.COMPANY_NAME FROM T_FD_INVOICE TFI left join (select INVOICE_ID, REGEXP_REPLACE ( LISTAGG (TO_CHAR(TFID.SHIP_NAME||'_'||TFID.VOYAGE), ',') WITHIN GROUP (ORDER BY INVOICE_ID), '([^,]+)(,\1)+', '\1' ) ship_name from T_FD_INVOICE_DETAIL TFID group by TFID.INVOICE_ID) ttt on ttt.INVOICE_ID = TFI.id WHERE TFI.STATUS = 1 and TFI.CREATE_TIME>TO_DATE('2024-10-31 12:00:00', 'YYYY-MM-DD HH24:MI:SS') UNION ALL SELECT '退还' AS DETAIL_TYPE, DECODE(TFDD.INVOICE_PREPAY_AMOUNT,NULL,0,TFDD.INVOICE_PREPAY_AMOUNT * -1) AS AMOUNT, '' "shipVoyageName", TO_DATE(TFDD.CREATE_TIME,'YYYY-MM-DD HH24:MI:SS'), TFD.CUSTOMER_ID, TO_CHAR(TFD.PREPAYMENT_TYPE_CODE), TO_CHAR(TFD.DEBTORPAYMENT_NO), TFDD.CREATE_BY_NAME, TFD.COMPANY_NAME FROM T_FD_DEBTORPAYMENT TFD INNER JOIN T_FD_DEBTORPAYMENT_DETAIL TFDD ON TFD.ID = TFDD.DEBTORPAYMENT_ID WHERE TFD.STATUS = 1 AND TFDD.DEBTORPAY_PAYMENT_TYPE_CODE = '30' ) T
T.CUSTOMER_ID = #{customerId,jdbcType=VARCHAR} AND T.PREPAYMENT_TYPE_CODE = #{prepaymentTypeCode,jdbcType=VARCHAR}
and to_char(T.PAYMENT_TIME,'YYYY-MM-DD') >= #{searchStartTime}
and to_char(T.PAYMENT_TIME,'YYYY-MM-DD') <= #{searchEndTime}
and T.BUSINESS_NO LIKE #{businessNoLike}
and T.DETAIL_TYPE NOT IN ('货物预缴','船舶押金')
ORDER BY T.PAYMENT_TIME DESC

SELECT TBT.TRUST_NO || '_' || tbci.cargo_info_no || '_'|| tbci.cargo_name ||' / '||TBTC.CARGO_OWNER_NAME||'/'||TDS.SHIP_NAME||'_'||TDSI.VOYAGE AS "label", TBT.TRUST_NO, TBT.ID AS "trustId", tbci.id cargo_info_id, TBTC.CARGO_OWNER_NAME, TBTC.CARGO_OWNER_ID, TBT.ID, TBTC.EST_AMOUNT AS "ESTAmount" FROM T_BUS_TRUST TBT LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID left join t_bus_cargo_info tbci on TBTC.cargo_info_id = tbci.id left join T_DIS_SHIPVOYAGE_ITEM TDSI on TDSI.id = tbci.SHIPVOYAGE_ITEM_ID left join T_DIS_SHIPVOYAGE TDS on TDS.id = TDSI.SHIPVOYAGE_ID WHERE TBT.COMPANY_ID = #{companyId,jdbcType=BIGINT} and tbci.IS_PRE_PAY != '30' and tbci.CREATE_TIME > to_date('2024-08-20 00:00:00','yyyy-MM-dd hh24:mi:ss') AND (TBT.TYPE = '卸船' OR TBT.TYPE IN ('集港', '拆箱集港'))
AND TBT.ID = #{id,jdbcType=BIGINT}
AND tbci.ID = #{cargoInfoId,jdbcType=BIGINT}
AND tbci.CARGO_OWNER_ID = #{customerId,jdbcType=BIGINT}
ORDER BY RELEASE_TIME desc

select ID,PREPAYMENT_AMOUNT,UTILIZED_AMOUNT,PREPAYMENT_CODE from T_FD_BANK_CUSTOMER_PREPAYMENT
where STATUS = '1' AND PREPAY_MODE_CODE = '10'

    AND CUSTOMER_ID = #{customerId}


    AND PREPAYMENT_TYPE_CODE = #{prepaymentTypeCode,jdbcType=VARCHAR}

order by CREATE_TIME desc

mapper.update:
UPDATE
T_FD_BANK_CUSTOMER_PREPAYMENT
SET
UTILIZED_AMOUNT = #{utilizedAmount,jdbcType=DECIMAL}


        AND id = #{id}


        AND PREPAYMENT_CODE = #{prepaymentCode}

mapper.select:
select sum(PREPAYMENT_AMOUNT-UTILIZED_AMOUNT) CUSTOMER_AMOUNT from
T_FD_BANK_CUSTOMER_PREPAYMENT

    CUSTOMER_ID = #{customerId}
    and STATUS = #{status}
    and PREPAYMENT_TYPE_CODE = #{prepaymentTypeCode}

select *
from T_FD_BANK_CUSTOMER_PREPAYMENT
where status = '1' and cargo_info_id  = #{cargoInfoId,jdbcType=BIGINT}
